+    const uint expert_nibble_base = e * N * D + n * D;
+    const uint expert_scale_base  = e * N * n_blocks + n * n_blocks;
+    const uint expert_zp_base     = e * N * zp_per_row + n * zp_per_row;
+    const uint expert_bias_base   = e * N + n;
